    expect(isZero(2e-6)).toBe(false);
    expect(isZero(-2e-6)).toBe(false);
    expect(isZero(1)).toBe(false);
  });

  it('honors a custom eps', () => {
    expect(isZero(0.4, 0.5)).toBe(true);
    expect(isZero(0.6, 0.5)).toBe(false);
  });
});
