    expect(eq(0, 5e-7)).toBe(true);        // |diff| = 5e-7 <  1e-6
    expect(eq(-1, -1 - 5e-7)).toBe(true);  // works on negatives
    expect(eq(0, 1e-6)).toBe(true);        // |diff| = 1e-6 <= 1e-6 -> inclusive
