    expect(eq(1, 1.4, 0.5)).toBe(true);   // |diff| = 0.4 <= 0.5
    expect(eq(1, 1.5, 0.5)).toBe(true);   // |diff| = 0.5 <= 0.5 (0.5 and 1.5 are exact doubles)
    expect(eq(1, 1.6, 0.5)).toBe(false);  // |diff| = 0.6 > 0.5
