    expect(XY_PLANE.x).toEqual({ x: 1, y: 0, z: 0 });
    expect(XY_PLANE.y).toEqual({ x: 0, y: 1, z: 0 });
    expect(XY_PLANE.z).toEqual({ x: 0, y: 0, z: 1 });
