export type KernelError = {
  code: 'openLoop' | 'selfIntersect' | 'degenerate';
  msg: string;
  entityIds: string[];
};

export type Result<T> = { ok: true; value: T } | { ok: false; error: KernelError };

export function ok<T>(value: T): Result<T> {
