// M1 profiles: line segments only, single outer loop, no holes.

export type SketchEntId = string;

export type Seg = { id: SketchEntId; a: Vec2; b: Vec2 };

/**
 * Closed loop: segs[i].b is EXACTLY the same object as segs[(i+1)%n].a.
